def handle_vex_result(vex_result, thread_id, customer_email):
    if not vex_result.passed:
        failures = vex_result.failures

        if 'pii_filtering' in failures:
            log_security_incident(customer_email, 'PII detected')
            return {'action': 'block', 'reason': 'PII violation'}

        if 'policy_compliance' in failures:
            create_internal_ticket(
                subject=f"Policy violation in thread {thread_id}",
                details=vex_result.failures
            )
            return {'action': 'escalate_internal'}

        if vex_result.escalation_score > 0.8:
            assign_to_senior_agent(thread_id)
            return {'action': 'escalate_human'}

    return {'action': 'approve'}
